#include<bits/stdc++.h>
using namespace std;
int f[5001],g[5001][5001],a[5001];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            f[i]=0;
            for(int j=1;j<=n;j++)
            {
                g[i][j]=0;
            }
        }
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        for(int i=1;i<=n;i++)
        {
            static int cnt[5001];
            memset(cnt,0,sizeof(cnt));
            int max1=0;
            auto len=[](int l,int r)
            {
                return r-l+1;
            };
            for(int j=i;j<=n;j++)
            {
                cnt[a[j]]++;
                max1=max(max1,cnt[a[j]]);
                if(max1<=(len(i,j)>>1)&&(len(i,j)%2==0))
                {
                    g[i][j]=1;
                }
                else
                {
                    g[i][j]=0;
                }
            }
        }
        int ans=0;
        g[1][0]=1;
        for(int i=1;i<=n;i++)
        {
            f[i]=g[1][i-1];
            for(int j=1;j<i;j++)
            {
                if(f[j]>0&&a[i]==a[j]&&((j+1>i-1)||g[j+1][i-1]))
                {
                    f[i]=max(f[i],f[j]+1);
                }
            }
            if(i==n||g[i+1][n])
            {
                ans=max(ans,f[i]);
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
